// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

type euint128 is uint256;
type ebool is uint256;

library FHE {
    function asEuint128(uint128 value) internal pure returns (euint128) {
        return euint128.wrap(uint256(value));
    }

    function add(
        euint128 lhs,
        euint128 rhs
    ) internal pure returns (euint128) {
        return euint128.wrap(euint128.unwrap(lhs) + euint128.unwrap(rhs));
    }

    function sub(
        euint128 lhs,
        euint128 rhs
    ) internal pure returns (euint128) {
        uint256 left = euint128.unwrap(lhs);
        uint256 right = euint128.unwrap(rhs);
        require(left >= right, "FHE shim: underflow");
        return euint128.wrap(left - right);
    }

    function gte(
        euint128 lhs,
        euint128 rhs
    ) internal pure returns (ebool) {
        return ebool.wrap(euint128.unwrap(lhs) >= euint128.unwrap(rhs) ? 1 : 0);
    }

    function select(
        ebool condition,
        euint128 whenTrue,
        euint128 whenFalse
    ) internal pure returns (euint128) {
        return ebool.unwrap(condition) == 1 ? whenTrue : whenFalse;
    }

    function allowThis(euint128) internal pure {}

    function allow(euint128, address) internal pure {}
}

